// Conservation status for a species by its IOC common name. Unknown or
// unassessed species return 'NE' (Not Evaluated).
export function statusFor(name: string): IUCNStatusCode {
  return IUCN_STATUS[name] ?? 'NE';
}

export default IUCN_STATUS;
